import React, { useState } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import api from '../api';
import './Login.css';

export default function VerifyComplete() {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const token = searchParams.get('token');

  const [password, setPassword] = useState('');
  const [passwordConfirm, setPasswordConfirm] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const validatePassword = (pw) => {
    const hasLength = pw.length >= 10;
    const hasNumber = /[0-9]/.test(pw);
    const hasSpecial = /[!@#$%^&*(),.?":{}|<>]/.test(pw);
    return hasLength && hasNumber && hasSpecial;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    if (!validatePassword(password)) {
      setError('비밀번호는 10자 이상, 숫자, 특수기호를 포함해야 합니다.');
      return;
    }
    if (password !== passwordConfirm) {
      setError('비밀번호가 일치하지 않습니다.');
      return;
    }

    setLoading(true);
    try {
      await api.post('/api/auth/set-password', { token, password });
      navigate('/login?verified=true');
    } catch (err) {
      setError(err.response?.data?.message || '오류가 발생했습니다.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-page">
      <div className="login-card">
        <div style={{ fontFamily: 'Arial Black', fontStyle: 'italic', fontSize: 24, textAlign: 'center', marginBottom: 8, color: '#111' }}>
          kairos
        </div>
        <p style={{ textAlign: 'center', fontSize: 13, color: '#999', marginBottom: 24 }}>
          이메일 인증이 완료되었습니다.<br />비밀번호를 입력해주세요.
        </p>

        <form onSubmit={handleSubmit} className="login-form">
          <div className="login-field">
            <label>비밀번호</label>
            <input
              type="password"
              value={password}
              onChange={e => setPassword(e.target.value)}
              placeholder="10자 이상, 숫자, 특수기호 포함"
              required
            />
          </div>
          <div className="login-field">
            <label>비밀번호 확인</label>
            <input
              type="password"
              value={passwordConfirm}
              onChange={e => setPasswordConfirm(e.target.value)}
              required
            />
          </div>

          {error && <p className="login-error">{error}</p>}

          <button type="submit" className="login-btn-black" disabled={loading}>
            {loading ? '...' : '완료'}
          </button>
        </form>
      </div>
    </div>
  );
}
